#!/usr/bin/env bash
#
# Generated by scripts/gen.py from scripts/issues.json. Do not edit by hand.
#
# Creates the GitHub repo, labels, milestones, and all issues via the gh CLI.
#
# Usage: ./scripts/create_github.sh <owner>/<repo> [--public|--private]
#
set -euo pipefail

if [[ $# -lt 1 ]]; then
  echo "Usage: $0 <owner>/<repo> [--public|--private]" >&2
  exit 1
fi

REPO="$1"; shift
VISIBILITY="--private"
while [[ $# -gt 0 ]]; do
  case "$1" in
    --public)  VISIBILITY="--public" ;;
    --private) VISIBILITY="--private" ;;
    *) echo "Unknown arg: $1" >&2; exit 1 ;;
  esac
  shift
done

echo "==> Verifying gh authentication"
gh auth status >/dev/null

echo "==> Creating repo $REPO ($VISIBILITY)"
if gh repo view "$REPO" >/dev/null 2>&1; then
  echo "    repo already exists, skipping creation"
else
  gh repo create "$REPO" $VISIBILITY \
    --description 'A tiny web game where you try to out-predict a small char-level language model, one word at a time.' \
    --source=. --remote=origin --push
fi

echo "==> Creating labels"
gh label create 'area:model' --repo "$REPO" --color 1d76db --description 'Char-level GPT definition, tokenizer, training' --force
gh label create 'area:server' --repo "$REPO" --color 0e8a16 --description 'FastAPI app, puzzle generation, rollout, scoring' --force
gh label create 'area:web' --repo "$REPO" --color 5319e7 --description 'Single-page frontend' --force
gh label create 'area:infra' --repo "$REPO" --color b60205 --description 'Project skeleton, tooling, deployment' --force
gh label create 'area:docs' --repo "$REPO" --color c2e0c6 --description 'Documentation and run instructions' --force
gh label create 'enhancement' --repo "$REPO" --color a2eeef --description 'Improves an existing capability' --force

echo "==> Creating milestones"
# gh has no native milestone command; use the REST API. 422 means it already exists.
gh api "repos/$REPO/milestones" --silent -f title='M1: MVP' -f description='The full loop playable end to end on one corpus, using a simple single-token puzzle.' >/dev/null 2>&1 || echo "    milestone M1: MVP exists or skipped"
gh api "repos/$REPO/milestones" --silent -f title='M2: Next-word puzzles' -f description='Upgrade the mechanic to the full next-word greedy rollout with probability-mass scoring.' >/dev/null 2>&1 || echo "    milestone M2: Next-word puzzles exists or skipped"
gh api "repos/$REPO/milestones" --silent -f title='M3: Multiple corpora' -f description='Train and serve several corpora; let the player choose which book to play.' >/dev/null 2>&1 || echo "    milestone M3: Multiple corpora exists or skipped"
gh api "repos/$REPO/milestones" --silent -f title='M4: Polish & deploy' -f description='Session scoring, a real design pass, and deployment + run docs.' >/dev/null 2>&1 || echo "    milestone M4: Polish & deploy exists or skipped"

echo "==> Creating issues"
gh issue create --repo "$REPO" \
  --title 'Project skeleton, dependencies, and /health' \
  --milestone 'M1: MVP' \
  --label 'area:infra' \
  --body-file - <<'WORDGUESS_ISSUE_BODY'
Stand up the repository skeleton so every later issue has a home. Create the Python package layout under model/ and server/, a requirements.txt (or pyproject) pinning torch, fastapi, uvicorn, a minimal FastAPI app exposing GET /health, and a short dev-setup section in the README explaining how to create a venv, install deps, and run the server.

## Acceptance criteria

- [ ] A virtualenv can be created and `pip install -r requirements.txt` succeeds on CPU-only machines.
- [ ] `uvicorn server.app:app` starts without error.
- [ ] `GET /health` returns `{"status": "ok"}` with HTTP 200.
- [ ] README documents the exact setup + run commands.
- [ ] model/, server/, web/, corpora/ exist with package __init__ files where appropriate.

## Out of scope

- No model definition, training, or puzzle logic yet.
- No frontend beyond what already exists in web/.
- No Docker or deployment config (that is M4).
WORDGUESS_ISSUE_BODY

gh issue create --repo "$REPO" \
  --title 'Char-level GPT model definition (nanoGPT-style)' \
  --milestone 'M1: MVP' \
  --label 'area:model' \
  --body-file - <<'WORDGUESS_ISSUE_BODY'
Define a trimmed char-level GPT in the nanoGPT lineage in model/: token + positional embeddings, a few transformer blocks with causal self-attention, LayerNorm, and a linear head. Provide a small config dataclass with defaults (n_layer=4, n_head=4, n_embd=128, block_size=128). Keep it CPU-runnable and readable in one sitting.

## Acceptance criteria

- [ ] A `GPT` module and a `GPTConfig` dataclass exist in model/.
- [ ] A forward pass on a random `(batch, block_size)` int tensor returns logits shaped `(batch, block_size, vocab_size)`.
- [ ] Causal masking is applied so position t never attends to positions > t.
- [ ] Model instantiates and runs a forward pass on CPU with the default config.
- [ ] Code favors clarity: named sub-modules, short docstrings, no premature abstraction.

## Out of scope

- No training loop (separate issue).
- No tokenizer (separate issue).
- No generation/sampling helpers beyond a plain forward pass.
